// TestUpsertBatch_RunsSearchableViaGenericFTS verifies that a
// dependent-resource row stored via UpsertBatch — the exact path dependent
// sync uses (upsertResourceBatch -> UpsertBatch) — is reachable through the
// generic resources_fts index via Store.Search. That index is the substrate
// both `search` surfaces query (the empty-type search directly, and the
// non-FTS5 `--type runs` fallback), so populating it is the
// precondition issue #2629 reported missing — dependent resources stored in
// the typed table but absent from any FTS index. This asserts the store layer
// where the claimed defect lived; it does not exercise the CLI search wiring.
func TestUpsertBatch_RunsSearchableViaGenericFTS(t *testing.T) {
	dbPath := filepath.Join(t.TempDir(), "data.db")
	s, err := Open(dbPath)
	if err != nil {
		t.Fatalf("open: %v", err)
	}
	defer s.Close()

	// resources_fts indexes the full JSON blob, so a distinctive token in any
	// field is matchable regardless of which columns runs declares.
	const probe = "zqxjpp2629probe"
	items := []json.RawMessage{
		json.RawMessage(`{"id": "search-001", "pp_fts_probe": "` + probe + `", "workflows_id": "parent-A", "parent_id": "parent-A"}`),
	}
	stored, _, err := s.UpsertBatch("runs", items)
	if err != nil {
		t.Fatalf("UpsertBatch: %v", err)
	}
	// Assert the probe row actually landed before searching for it: a PK
	// extraction miss would leave stored == 0, and the FTS check below would
	// then fail with a misleading "stored but not searchable" message.
	if stored != 1 {
		t.Fatalf("UpsertBatch stored %d rows, want 1 (probe row dropped before the FTS check)", stored)
	}

	results, err := s.Search(probe, 50)
	if err != nil {
		t.Fatalf("Search: %v", err)
	}
	if len(results) == 0 {
		t.Fatalf("dependent resource %q stored but not searchable via generic resources_fts (issue #2629)", "runs")
	}
}

// TestUpsertBatch_PopulatesWorkflowsTestTable verifies that UpsertBatch
// dispatches paginated items into both the generic resources table AND the
// typed workflows_test table. Regression for issue #268: before the fix, paginated
// syncs only filled the generic resources table, so domain commands that
// query the typed table saw zero rows.
func TestUpsertBatch_PopulatesWorkflowsTestTable(t *testing.T) {
	dbPath := filepath.Join(t.TempDir(), "data.db")
	s, err := Open(dbPath)
	if err != nil {
		t.Fatalf("open: %v", err)
	}
	defer s.Close()

	items := []json.RawMessage{
		json.RawMessage(`{"id": "test-001", "workflows_id": "test-parent-001"}`),
		json.RawMessage(`{"id": "test-002", "workflows_id": "test-parent-001"}`),
		json.RawMessage(`{"id": "test-003", "workflows_id": "test-parent-001"}`),
	}
	if _, _, err := s.UpsertBatch("workflows_test", items); err != nil {
		t.Fatalf("UpsertBatch: %v", err)
	}

	db := s.DB()

	var generic int
	if err := db.QueryRow(`SELECT COUNT(*) FROM resources WHERE resource_type = ?`, "workflows_test").Scan(&generic); err != nil {
		t.Fatalf("count resources: %v", err)
	}
	if generic != len(items) {
		t.Fatalf("resources count = %d, want %d", generic, len(items))
	}

	var typed int
	typedQuery := fmt.Sprintf(`SELECT COUNT(*) FROM "%s"`, "workflows_test")
	if err := db.QueryRow(typedQuery).Scan(&typed); err != nil {
		t.Fatalf("count workflows_test: %v", err)
	}
	if typed != len(items) {
		t.Fatalf("workflows_test count = %d, want %d (typed table not populated by UpsertBatch)", typed, len(items))
	}
}

// TestUpsertBatch_TypedFailureDoesNotStrandWorkflowsTestGeneric exercises
// the savepoint isolation around the typed-table dispatch. The fixture omits
// the NOT NULL parent FK column so the typed insert fails; the savepoint
// rolls back only the typed projection. The generic resources row inserted
// just before must survive. Regression for issue #1392, where a single
// outer transaction caused typed-table failures to cascade and silently
// discard every successfully fetched API row.
func TestUpsertBatch_TypedFailureDoesNotStrandWorkflowsTestGeneric(t *testing.T) {
	dbPath := filepath.Join(t.TempDir(), "data.db")
	s, err := Open(dbPath)
	if err != nil {
		t.Fatalf("open: %v", err)
	}
	defer s.Close()

	// Items deliberately omit "workflows_id" so the typed NOT NULL
	// constraint fires.
	items := []json.RawMessage{
		json.RawMessage(`{"id": "orphan-001"}`),
		json.RawMessage(`{"id": "orphan-002"}`),
		json.RawMessage(`{"id": "orphan-003"}`),
	}
	stored, extractFailures, err := s.UpsertBatch("workflows_test", items)
	if err != nil {
		t.Fatalf("UpsertBatch: %v (typed-table failure must not propagate)", err)
	}
	if stored != len(items) {
		t.Fatalf("stored = %d, want %d (generic resources rows must land even when typed table fails)", stored, len(items))
	}
	if extractFailures != 0 {
		t.Fatalf("extractFailures = %d, want 0", extractFailures)
	}

	db := s.DB()

	var generic int
	if err := db.QueryRow(`SELECT COUNT(*) FROM resources WHERE resource_type = ?`, "workflows_test").Scan(&generic); err != nil {
		t.Fatalf("count resources: %v", err)
	}
	if generic != len(items) {
		t.Fatalf("resources count = %d, want %d (savepoint rollback must not undo generic insert)", generic, len(items))
	}

	var typed int
	typedQuery := fmt.Sprintf(`SELECT COUNT(*) FROM "%s"`, "workflows_test")
	if err := db.QueryRow(typedQuery).Scan(&typed); err != nil {
		t.Fatalf("count workflows_test: %v", err)
	}
	if typed != 0 {
		t.Fatalf("workflows_test count = %d, want 0 (typed insert violated NOT NULL on %q)", typed, "workflows_id")
	}
}

